mapper.select:
SELECT COUNT(PLACE_ID)
FROM place
WHERE PLACE_TYPE = #{value}

mapper.update:
UPDATE place
SET LIKE_COUNT = LIKE_COUNT + 1
WHERE PLACE_ID = #{value}

mapper.select:
SELECT LIKE_COUNT
FROM place
WHERE PLACE_TYPE = #{placeType}
  AND PLACE_ID = #{placeId}

mapper.update:
UPDATE place
SET LIKE_COUNT = LIKE_COUNT + 1
WHERE PLACE_ID = #{value}

mapper.select:
SELECT placeId, title, firstImage, addr1, mapx, mapy, likeCount, placeType FROM ( SELECT PLACE_ID AS placeId, TITLE AS title, FIRST_IMAGE AS firstImage, ADDR1 AS addr1, MAPX AS mapx, MAPY AS mapy, LIKE_COUNT AS likeCount, #{placeType} AS placeType, (6371 * 2 * ASIN(SQRT( POWER(SIN((CAST(MAPY AS DOUBLE) - CAST(#{centerLat} AS DOUBLE)) * 0.017453292519943295 / 2), 2) + COS(CAST(MAPY AS DOUBLE) * 0.017453292519943295) * COS(CAST(#{centerLat} AS DOUBLE) * 0.017453292519943295) * POWER(SIN((CAST(MAPX AS DOUBLE) - CAST(#{centerLon} AS DOUBLE)) * 0.017453292519943295 / 2), 2) ))) AS distance_km FROM place WHERE PLACE_TYPE = #{placeType} AND MAPX IS NOT NULL AND MAPY IS NOT NULL
AND LCLSSYSTM3 = #{category}
AND (TITLE LIKE #{keywordPattern} OR ADDR1 LIKE #{keywordPattern})
) AS p WHERE distance_km <= #{radiusKm}
ORDER BY likeCount DESC, distance_km ASC
ORDER BY distance_km ASC
